'use client';

import { useState, useRef } from 'react';
import { MapContainer, TileLayer, Marker, useMap, useMapEvents } from 'react-leaflet';
import { LatLngExpression, LatLngTuple, Icon } from 'leaflet';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { List, ListItem } from '@/components/ui/list';
import 'leaflet/dist/leaflet.css';
import { Loader2, Search } from 'lucide-react';

interface MapSelectorProps {
  onLocationSelect: (address: string) => void;
}

// Default center (e.g., Bogotá, Colombia)
const defaultCenter: LatLngTuple = [4.711, -74.0721];
const defaultZoom = 13;

// Fix for default marker icon in Next.js
const markerIcon = new Icon({
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});


interface SearchResult {
  place_id: number;
  lat: string;
  lon: string;
  display_name: string;
}

function MapClickHandler({ onMapClick }: { onMapClick: (latlng: { lat: number; lng: number }) => void }) {
  useMapEvents({
    click(e) {
      onMapClick(e.latlng);
    },
  });
  return null;
}

function ChangeView({ center, zoom }: { center: LatLngExpression; zoom: number }) {
  const map = useMap();
  map.setView(center, zoom);
  return null;
}

export function MapSelector({ onLocationSelect }: MapSelectorProps) {
  const [center, setCenter] = useState<LatLngExpression>(defaultCenter);
  const [markerPosition, setMarkerPosition] = useState<LatLngTuple | null>(defaultCenter);
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState<SearchResult[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  const reverseGeocode = async (lat: number, lng: number) => {
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=jsonv2&lat=${lat}&lon=${lng}`);
      const data = await response.json();
      if (data && data.display_name) {
        onLocationSelect(data.display_name);
      }
    } catch (error) {
      console.error('Error reverse geocoding:', error);
    }
  };
  
  const handleMapClick = (latlng: { lat: number, lng: number }) => {
    setMarkerPosition([latlng.lat, latlng.lng]);
    reverseGeocode(latlng.lat, latlng.lng);
  };

  const handleSearch = async () => {
    if (!searchTerm) return;
    setIsSearching(true);
    setSearchResults([]);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(searchTerm)}&format=json&addressdetails=1&limit=5`);
      const data: SearchResult[] = await response.json();
      setSearchResults(data);
    } catch (error) {
      console.error('Error searching location:', error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleSearchResultClick = (result: SearchResult) => {
    const lat = parseFloat(result.lat);
    const lon = parseFloat(result.lon);
    const newCenter: LatLngTuple = [lat, lon];
    setCenter(newCenter);
    setMarkerPosition(newCenter);
    onLocationSelect(result.display_name);
    setSearchResults([]);
  };

  return (
    <div className="relative h-full w-full flex flex-col gap-4">
      <div className="flex gap-2">
        <Input
          type="text"
          placeholder="Buscar dirección..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
          className="flex-grow shadow-md"
        />
        <Button onClick={handleSearch} disabled={isSearching} size="icon">
          {isSearching ? <Loader2 className="h-4 w-4 animate-spin" /> : <Search className="h-4 w-4" />}
        </Button>
      </div>

      {searchResults.length > 0 && (
         <Card className="shadow-lg max-h-48 overflow-y-auto">
            <List>
            {searchResults.map((result) => (
                <ListItem key={result.place_id} button onClick={() => handleSearchResultClick(result)}>
                <p className="text-sm font-medium">{result.display_name.split(',')[0]}</p>
                <p className="text-xs text-muted-foreground">{result.display_name.substring(result.display_name.indexOf(',') + 1)}</p>
                </ListItem>
            ))}
            </List>
        </Card>
      )}

      <div className="flex-grow rounded-md overflow-hidden">
        <MapContainer center={defaultCenter} zoom={defaultZoom} style={{ height: '100%', width: '100%' }}>
           <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            />
          <ChangeView center={center} zoom={defaultZoom} />
          <MapClickHandler onMapClick={handleMapClick} />
          {markerPosition && <Marker position={markerPosition} icon={markerIcon} />}
        </MapContainer>
      </div>
    </div>
  );
}

// Dummy components to satisfy imports if they are not in shadcn
const Card = ({ className, children }: { className?: string, children: React.ReactNode }) => (
    <div className={`rounded-lg border bg-card text-card-foreground ${className}`}>
        {children}
    </div>
)
